create table dirkspzm32.s_erp_rcv_kunden_auftr_pos (
    sid                  varchar2(2 char) default 01 not null enable,
    firma_nr             number(6, 0) default 1 not null enable,
    kunden_auftr_pos_id  number(*, 0) not null enable,
    status               varchar2(3 char) not null enable,
    auftrag              number(*, 5),
    pos_nr               number(*, 5),
    upos_nr              number(*, 5),
    adr_art              varchar2(1 char),
    adr_nr               varchar2(20 char),
    adr_liefer           varchar2(20 char),
    login_id             number(*, 0),
    arbeitsplatz_id      number(*, 0),
    artikel              varchar2(30 char),
    fa_nr                number(*, 5),
    fa_ag                number(*, 5),
    fa_upos              number(*, 5),
    charge               varchar2(60 char),
    seriennr             varchar2(20 char),
    strategie            varchar2(10 char),
    mhd                  date,
    kom_info             varchar2(40 char),
    soll_menge           number(*, 3),
    mengeneinheit        varchar2(10 char),
    wae_ziel             varchar2(30 char),
    besteller            varchar2(10 char),
    freigabe             varchar2(1 char),
    freigabe_datum       date,
    freigegeben_datum    date,
    order_datum          date,
    liefer_datum         date,
    fertig_datum         date,
    prioritaet           number(*, 0),
    anbruch              varchar2(1 char),
    min_mhd_tage         number(*, 12),
    min_reifezeit        number(*, 12),
    best_nr_kunde        varchar2(30 char),
    zeichnung_index      varchar2(10 char),
    li_nr                number(*, 5),
    li_pos_nr            number(*, 5),
    lam_sel1             varchar2(30 char),
    lam_sel2             varchar2(30 char),
    lam_sel3             varchar2(30 char),
    lam_sel4             varchar2(30 char),
    lam_sel5             varchar2(30 char),
    lam_sel6             varchar2(30 char),
    lam_sel7             varchar2(30 char),
    lam_sel8             varchar2(30 char),
    lam_sel9             varchar2(30 char),
    lam_sel10            varchar2(30 char),
    prod_params          varchar2(4000 char),
    ziel                 varchar2(30 char),
    created_date         date default sysdate not null enable,
    created_login_id     number(*, 0) default - 1 not null enable,
    last_change_date     date,
    last_change_login_id number(*, 0),
    fehler_code          number,
    fehler_text          varchar2(2500 char)
);

alter table dirkspzm32.s_erp_rcv_kunden_auftr_pos
    add constraint check_s_erp_rcv_kun_a_p_status
        check ( status in ( 'N', 'U', 'D', 'UE', 'DF',
                            'ERR' ) ) enable;

alter table dirkspzm32.s_erp_rcv_kunden_auftr_pos
    add constraint pk_s_erp_rcv_kunden_auftr_p
        primary key ( kunden_auftr_pos_id,
                      firma_nr,
                      sid )
            using index enable;


